# Category: path_traversal

local filename_arg = ngx.var.arg_filename

if not filename_arg then
    ngx.status = ngx.HTTP_BAD_REQUEST
    ngx.say("Error: No 'filename' argument provided (e.g., /download?filename=my/file.txt).")
    return
