-- !!! IMPORTANT: CONFIGURE YOUR BASE DIRECTORY HERE !!!
-- This should be an absolute path to prevent ambiguity and ensure security.
-- Example: "/usr/local/nginx/html/files/" or "/var/www/your_files_storage/"
-- Make sure this directory exists and Nginx worker process has read permissions.
local BASE_DIR = "/path/to/your/files/" -- <-- CHANGE THIS ABSOLUTE PATH TO YOUR FILE STORAGE

-- Ensure BASE_DIR ends with a slash for consistent path construction
if not BASE_DIR:match("/$") then
    BASE_DIR = BASE_DIR .. "/"
end

-- --- SECURITY SANITIZATION ---
-- A robust path resolution function to prevent directory traversal attacks.
-- It normalizes the path by resolving '.' and '..' components and ensures
-- the final path does not escape the provided base directory.
local function resolve_and_secure_path(base_dir, user_path)
    -- Sanitize input: Remove leading/trailing slashes from base_dir for internal processing
    local cleaned_base_dir = base_dir:gsub("^/+", ""):gsub("/+$", "")

    -- Split base directory into components
    local path_components = {}
    for comp in cleaned_base_dir:gmatch("[^/]+") do
        table.insert(path_components, comp)
    end

    -- Process user-provided path components
    for comp in user_path:gmatch("[^/]+") do
        if comp == ".." then
            -- If trying to go up from the base, or if path_components is empty
            if #path_components > 0 and path_components[#path_components] ~= ".." then
                table.remove(path_components) -- Go up one level
            else
                -- Attempt to go above the permitted base directory, or base itself is '..'
                return nil
            end
        elseif comp ~= "." and comp ~= "" then
            table.insert(path_components, comp)
        end
    end

    -- Reconstruct the full absolute path
    local resolved_path = "/" .. table.concat(path_components, "/")

    -- Final security check: Ensure the resolved path still starts with the base_dir
    -- This handles cases where path resolution might otherwise lead outside the intended scope.
    if not resolved_path:find("^" .. ngx.re.escape("/" .. cleaned_base_dir), 1) then
        return nil
    end

    return resolved_path
end

-- Reject paths containing backslashes as they are not standard for UNIX-like
-- file systems and might indicate an attempt to bypass security on Windows systems.
if filename_arg:find("\\") or filename_arg:find("%c") then -- %c matches control characters
    ngx.status = ngx.HTTP_FORBIDDEN
    ngx.say("Error: Invalid filename. Backslashes or control characters are not allowed.")
    return
end

-- Resolve and sanitize the path
local file_to_open = resolve_and_secure_path(BASE_DIR, filename_arg)

if not file_to_open then
    ngx.status = ngx.HTTP_FORBIDDEN
    ngx.say("Error: Invalid filename. Directory traversal attempt detected or path is outside base directory.")
    return
end

-- Attempt to open the file
local file, err = io.open(file_to_open, "rb") -- "rb" for binary read mode
if not file then
    if err == "No such file or directory" then
        ngx.status = ngx.HTTP_NOT_FOUND
        ngx.say("Error: File '" .. ngx.escape_uri(filename_arg) .. "' not found.")
    elseif err == "Permission denied" then
        ngx.status = ngx.HTTP_FORBIDDEN
        ngx.say("Error: Permission denied to access file '" .. ngx.escape_uri(filename_arg) .. "'.")
    else
        ngx.status = ngx.HTTP_INTERNAL_SERVER_ERROR
        ngx.say("Error: Could not open file '" .. ngx.escape_uri(filename_arg) .. "': " .. err)
    end
    return
end

-- Read the entire file content
local content = file:read("*a")
file:close()

if not content then
    ngx.status = ngx.HTTP_INTERNAL_SERVER_ERROR
    ngx.say("Error: Could not read content of file '" .. ngx.escape_uri(filename_arg) .. "'.")
