-- --- Set HTTP Headers ---

-- Set Content-Type header (a simple map, can be extended or replaced by a more comprehensive MIME type library)
local mime_type = "application/octet-stream" -- Default
local extension = filename_arg:match("%.([^%.]+)$")
if extension then
    extension = extension:lower()
    if extension == "txt" then mime_type = "text/plain"
    elseif extension == "html" then mime_type = "text/html"
    elseif extension == "css" then mime_type = "text/css"
    elseif extension == "js" then mime_type = "application/javascript"
    elseif extension == "json" then mime_type = "application/json"
    elseif extension == "xml" then mime_type = "application/xml"
    elseif extension == "jpg" or extension == "jpeg" then mime_type = "image/jpeg"
    elseif extension == "png" then mime_type = "image/png"
    elseif extension == "gif" then mime_type = "image/gif"
    elseif extension == "bmp" then mime_type = "image/bmp"
    elseif extension == "ico" then mime_type = "image/x-icon"
    elseif extension == "svg" then mime_type = "image/svg+xml"
    elseif extension == "pdf" then mime_type = "application/pdf"
    elseif extension == "zip" then mime_type = "application/zip"
    elseif extension == "tar" then mime_type = "application/x-tar"
    elseif extension == "gz" then mime_type = "application/gzip"
    elseif extension == "mp3" then mime_type = "audio/mpeg"
    elseif extension == "mp4" then mime_type = "video/mp4"
    elseif extension == "webm" then mime_type = "video/webm"
    end
end
ngx.header["Content-Type"] = mime_type

-- Set Content-Disposition to suggest filename for download or inline display
-- Extracts the base filename from the path to use in Content-Disposition
local base_filename_for_disposition = filename_arg:match("([^/]-)$") or "download"
-- Escape double quotes in filename for Content-Disposition header
base_filename_for_disposition = ngx.re.gsub(base_filename_for_disposition, '["]', '\\"', "jo")
ngx.header["Content-Disposition"] = 'inline; filename="' .. base_filename_for_disposition .. '"'

-- Set Content-Length for proper download progress indication
ngx.header["Content-Length"] = #content

